export type IndicatorVariant = 'unsaved' | 'new' | 'unread';
export type IndicatorSize = 'sm' | 'lg';

export interface IndicatorOptions {
  variant: IndicatorVariant;
  size?: IndicatorSize;
}

const VALID_VARIANTS: readonly IndicatorVariant[] = ['unsaved', 'new', 'unread'];
const VALID_SIZES: readonly IndicatorSize[] = ['sm', 'lg'];

/**
 * Creates an indicator badge element for positioning at the top-right corner
 * of a parent container. The parent must have `position: relative`.
 */
export function createIndicator(options: IndicatorOptions): HTMLSpanElement {
  const variant = VALID_VARIANTS.includes(options.variant) ? options.variant : 'unsaved';
  const size = options.size && VALID_SIZES.includes(options.size) ? options.size : 'lg';

  const el = document.createElement('span');
  el.className = `o9ds-indicator o9ds-indicator--${variant} o9ds-indicator--${size}`;
  el.setAttribute('aria-hidden', 'true');

  return el;
}

/**
 * Updates an existing indicator element's variant and/or size.
 */
export function updateIndicator(
  el: HTMLElement,
  options: Partial<IndicatorOptions>,
): void {
  if (options.variant !== undefined) {
    const variant = VALID_VARIANTS.includes(options.variant) ? options.variant : 'unsaved';
    VALID_VARIANTS.forEach(v => el.classList.remove(`o9ds-indicator--${v}`));
    el.classList.add(`o9ds-indicator--${variant}`);
  }

  if (options.size !== undefined) {
    const size = VALID_SIZES.includes(options.size) ? options.size : 'lg';
    VALID_SIZES.forEach(s => el.classList.remove(`o9ds-indicator--${s}`));
    el.classList.add(`o9ds-indicator--${size}`);
  }
}

/**
 * Removes an indicator element from the DOM and returns null for assignment cleanup.
 */
export function removeIndicator(el: HTMLElement | null): null {
  el?.remove();
  return null;
}
